@@ -0,0 +1,43 @@
+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+
+codeunit 30380 "Shpfy Copy Document Subscribers"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopyFieldsFromOldSalesHeader', '', false, false)]
+    local procedure ClearShopifyLinksOnHeaderCopy(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; MoveNegLines: Boolean; IncludeHeader: Boolean; FromDocType: Enum "Sales Document Type From"; RecalculateLines: Boolean)
+    begin
+        if not IncludeHeader then
+            exit;
+
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+        ToSalesHeader."Shpfy Refund Id" := 0;
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesDocument', '', false, false)]
+    local procedure ClearShopifyLinksOnLineCopy(FromDocumentType: Option; FromDocumentNo: Code[20]; var ToSalesHeader: Record "Sales Header"; FromDocOccurenceNo: Integer; FromDocVersionNo: Integer; IncludeHeader: Boolean; RecalculateLines: Boolean; MoveNegLines: Boolean)
+    var
+        SalesLine: Record "Sales Line";
+    begin
+        if not IncludeHeader then
+            exit;
+
+        SalesLine.SetRange("Document Type", ToSalesHeader."Document Type");
+        SalesLine.SetRange("Document No.", ToSalesHeader."No.");
+        if SalesLine.FindSet() then
+            repeat
+                if (SalesLine."Shpfy Order Line Id" <> 0) or (SalesLine."Shpfy Order No." <> '') or
+                   (SalesLine."Shpfy Refund Id" <> 0) or (SalesLine."Shpfy Refund Line Id" <> 0)
+                then begin
+                    SalesLine."Shpfy Order Line Id" := 0;
+                    SalesLine."Shpfy Order No." := '';
+                    SalesLine."Shpfy Refund Id" := 0;
+                    SalesLine."Shpfy Refund Line Id" := 0;
+                    SalesLine.Modify();
+                end;
+            until SalesLine.Next() = 0;
+    end;
+}

